import { useState } from "react";

function ExpenseForm({AddExpense}){
    const [name, setName] = useState("");
    const [expenses, setExpenses] = useState([]);
    const [totalBalance, setTotalBalance] = useState('');
    const [date, setDate] = useState("");


    const handleSubmit = async (e) => { //function for handling submission 
        e.preventDefault();        
        if (name && expenses && totalBalance && date) { // if all fields are not null
            const newExpense = {name, expenses, totalBalance, date}; // create a new expense object
            await AddExpense(newExpense); // insert expense into the expenseform
            // clear to restart submission after handling submit
            setName("");
            setExpenses("");
            setTotalBalance("");
            setDate("");
        } 
            else{
                alert("please fill out all fields");
            }
            
        
    }

    return(
    <form onSubmit={handleSubmit}>
        <h2>Register User</h2>
        <label htmlFor="name">Name:
            <input 
            type="text"  
            id="user-name" 
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
            />  
        </label>
        <label htmlFor=""></label>
        <button type="submit">Add User</button>
    </form>
)
};



export default ExpenseForm
